const payload = $json.result ?? $json;
const source = payload?.data ?? payload ?? {};
const tenantId = $("Estandarizar Variables").item.json.tenant_id || "";
const originalMsg = $("Estandarizar Variables").item.json.message || "";
const asText = (v) => typeof v === "string" ? v.trim() : "";
const content = asText(source.content) || asText(source.contenido) || asText(source.texto) || asText(payload?.content) || asText(payload?.result) || asText(payload?.message) || "";
const msgMatch = originalMsg.match(/obtener\\s+documento\\s+(.+)/i);
const title = asText(source.titulo) || asText(source.nombre) || (msgMatch ? msgMatch[1].trim() : "") || asText(source.filename) || "Documento";

if (!content) {
  return { tenant_id: tenantId, texto: "No pude obtener el documento solicitado.", response: "", ui_elements: [], source: "mcp_catolico_leer_documento" };
}

const preview = title + " — documento cargado en el panel lateral 👉";
const uiElements = [{ type: "sidebar", title: title, content: content }];

return { tenant_id: tenantId, texto: preview, response: content, ui_elements: uiElements, source: "mcp_catolico_leer_documento" };

const raw = $json;
let result = raw;

// Parsear respuesta MCP
if (Array.isArray(raw.content) && raw.content.length > 0) {
  const textEntry = raw.content.find(e => e && e.type === 'text');
  if (textEntry && textEntry.text) {
    try { result = JSON.parse(textEntry.text); } catch(e) {}
  }
} else if (raw.result) {
  result = typeof raw.result === 'string' ? (() => { try { return JSON.parse(raw.result); } catch(e) { return { content: raw.result }; } })() : raw.result;
}
if (result && result.content && Array.isArray(result.content)) {
  const inner = result.content.find(e => e && e.type === 'text');
  if (inner && inner.text) {
    try { result = JSON.parse(inner.text); } catch(e) {}
  }
}

const validacion = $('Validar Titulo Resumir').item.json;
const tenantId = validacion.tenant_id || 'catolico';
const content = (result && (result.content || result.contenido || result.texto || result.summary || '')).toString().trim()
  || (raw.content || '').toString().trim();
const titulo = (result && result.titulo) || validacion.titulo_encontrado || validacion.titulo_buscado || 'Documento';

if (!content || content.length < 20) {
  const errMsg = (result && result.error) || 'No pude generar el resumen del documento.';
  return [{json:{
    tenant_id: tenantId,
    texto: '❌ ' + errMsg,
    response: errMsg,
    ui_elements: [],
    source: 'mcp_catolico_resumir'
  }}];
}

// Construir advertencia si no hubo coincidencia exacta
let advertencia = '';
if (!validacion.coincidencia_exacta) {
  const top4List = (validacion.top4_similares || []).map(t => `  • ${t}`).join('\n');
  advertencia = `\n\n---\n⚠️ **Nota:** Pediste resumir _"${validacion.titulo_buscado}"_ pero no encontré ese título exacto en el catálogo. Se resumió el documento más similar: **"${titulo}"**.\n\n📋 Los 4 títulos más similares disponibles son:\n${top4List}`;
}

const previewSuffix = validacion.coincidencia_exacta ? '' : ' _(documento más similar)_';
const preview = `📄 Resumen de **${titulo}** listo en el panel lateral 👉${previewSuffix}`;

return [{json:{
  tenant_id: tenantId,
  texto: preview,
  response: content + advertencia,
  ui_elements: [{ type: 'sidebar', title: 'Resumen: ' + titulo, content: content + advertencia }],
  source: 'mcp_catolico_resumir'
}}];

// Extraer nombre del documento buscado del mensaje original
const message = $('Estandarizar Variables').item.json.message || '';
const msgNorm = message.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// Detectar qué quiso resumir el usuario (texto después de resumir/sintetizar/síntesis)
const resumeMatch = msgNorm.match(/\b(?:resum[a-z]*|sintetiz[a-z]*|sintesis)\s+(?:(?:el|la|los|las|del?|un|una)\s+(?:documento\s+)?)?(.+?)(?:\s+(?:por\s+favor|porfavor)|\s*[.?!]*\s*$)/i);
const docQuery = resumeMatch ? resumeMatch[1].trim() : msgNorm;

// Leer la lista de documentos del nodo anterior
const raw = $json;
let result = raw;

// Parsear respuesta MCP (puede venir envuelta en content[])
if (Array.isArray(raw.content) && raw.content.length > 0) {
  const textEntry = raw.content.find(e => e && e.type === 'text');
  if (textEntry && textEntry.text) {
    try { result = JSON.parse(textEntry.text); } catch(e) {}
  }
} else if (raw.result) {
  result = raw.result;
}
if (result && result.content && Array.isArray(result.content)) {
  const inner = result.content.find(e => e && e.type === 'text');
  if (inner && inner.text) {
    try { result = JSON.parse(inner.text); } catch(e) {}
  }
}

const documentos = (result && Array.isArray(result.documentos)) ? result.documentos
  : (result && result.data && Array.isArray(result.data.documentos)) ? result.data.documentos
  : [];

// Función de similitud Jaccard sobre palabras
function tokenize(str) {
  return str.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .split(/\W+/).filter(w => w.length > 2);
}
function jaccard(tokA, tokB) {
  const setA = new Set(tokA);
  const setB = new Set(tokB);
  const inter = [...setA].filter(x => setB.has(x)).length;
  const union = new Set([...setA, ...setB]).size;
  return union === 0 ? 0 : inter / union;
}

const queryTokens = tokenize(docQuery);
const queryNorm = docQuery.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const scored = documentos.map(doc => {
  const tituloNorm = (doc.titulo || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const fileNorm = (doc.filename || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const jTitle = jaccard(queryTokens, tokenize(doc.titulo || ''));
  const jFile  = jaccard(queryTokens, tokenize(doc.filename || ''));
  const score  = Math.max(jTitle, jFile);
  const exactMatch = tituloNorm === queryNorm
    || tituloNorm.includes(queryNorm)
    || fileNorm.includes(queryNorm);
  return { titulo: doc.titulo || '', filename: doc.filename || '', score, exactMatch };
}).sort((a, b) => {
  if (a.exactMatch !== b.exactMatch) return a.exactMatch ? -1 : 1;
  return b.score - a.score;
});

const best = scored[0] || null;
const top4 = scored.slice(0, 4).map(d => d.titulo || d.filename);
const coincidenciaExacta = !!(best && (best.exactMatch || best.score >= 0.7));

return [{ json: {
  titulo_buscado: docQuery,
  titulo_encontrado: best ? best.titulo : '',
  filename_encontrado: best ? best.filename : '',
  score: best ? best.score : 0,
  coincidencia_exacta: coincidenciaExacta,
  top4_similares: top4,
  message_original: message,
  tenant_id: $('Estandarizar Variables').item.json.tenant_id || 'catolico',
  sin_documentos: documentos.length === 0
}}];

const data = $json;
const tenantId = $('Estandarizar Variables').item.json.tenant_id || 'default';
const content = data?.choices?.[0]?.message?.content
  || data?.content
  || data?.result
  || data?.message
  || 'Sin respuesta del asistente.';
return {
  tenant_id: tenantId,
  response: content,
  texto: content.length > 160 ? content.substring(0, 160) + '... *(ver panel lateral)*' : content,
  ui_elements: []
};

