={{ (() => {
  const rawMessage = String($json.message || '').toLowerCase();
  const normalizedMessage = rawMessage.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const weekdayMatch = normalizedMessage.match(/\b(domingo|lunes|martes|miercoles|jueves|viernes|sabado)\b/);
  let fecha = 'hoy';

  // Formato DD-MM-AAAA (viene del date picker)
  const ddmmyyyyMatch = normalizedMessage.match(/\b(\d{1,2})-(\d{1,2})-(\d{4})\b/);
  // Formato YYYY-MM-DD
  const isoMatch = normalizedMessage.match(/\b(\d{4})-(\d{2})-(\d{2})\b/);

  if (ddmmyyyyMatch) {
    const [, d, m, y] = ddmmyyyyMatch;
    fecha = `${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`;
  } else if (isoMatch) {
    fecha = isoMatch[0];
  } else if (/\bpasado\s+manana\b/.test(normalizedMessage)) {
    const targetDate = new Date();
    targetDate.setHours(0, 0, 0, 0);
    targetDate.setDate(targetDate.getDate() + 2);
    fecha = targetDate.toISOString().slice(0, 10);
  } else if (/\bmanana\b/.test(normalizedMessage)) {
    const targetDate = new Date();
    targetDate.setHours(0, 0, 0, 0);
    targetDate.setDate(targetDate.getDate() + 1);
    fecha = targetDate.toISOString().slice(0, 10);
  } else if (weekdayMatch) {
    const weekdayMap = { domingo: 0, lunes: 1, martes: 2, miercoles: 3, jueves: 4, viernes: 5, sabado: 6 };
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const currentDay = today.getDay();
    const targetDay = weekdayMap[weekdayMatch[1]];
    const dayOffset = (targetDay - currentDay + 7) % 7;
    const targetDate = new Date(today);
    targetDate.setDate(today.getDate() + dayOffset);
    fecha = targetDate.toISOString().slice(0, 10);
  }

  return {
    tool_name: 'catolico_lecturas_dia',
    arguments: { fecha },
  };
})() }}
